import React from 'react'

import OrcamentoButton from '../BotaoOrcamento/OrcamentoButton.jsx'
import Presentation from '../InPages/Presentation/Presentation.jsx'

import "../Peres Seguranca/peresseguranca.css"
import Main from '../InPages/Main/Main.jsx'

const PeresSeguranca = () => {
  return (
    <>
      <section id="peresseguranca" className="img">

        <Main title="Peres Segurança" slogan={"Qualidade e Confiança"} />

        <Presentation
          title={"Peres Segurança"}
          content={"No mundo atual, o entendimento das metas propostas talvez venha a ressaltar a relatividade de alternativas às soluções ortodoxas."}
        />

      </section>

    </>


  )
}

export default PeresSeguranca
